(function(){const drop=()=>document.getElementById('csv-drop');document.addEventListener('dragover',e=>{if(!drop())return;if(e.target===drop()||drop().contains(e.target)){e.preventDefault();drop().classList.add('dragover');}});document.addEventListener('dragleave',e=>{if(drop())drop().classList.remove('dragover');});document.addEventListener('drop',e=>{if(!drop())return;if(e.target===drop()||drop().contains(e.target)){e.preventDefault();drop().classList.remove('dragover');const f=e.dataTransfer.files&&e.dataTransfer.files[0];if(f){_csvFile=f;document.getElementById('csv-drop-text').textContent=`📄 ${f.name} (${(f.size/1024).toFixed(1)} KB)`;if(!document.getElementById('csv-label').value.trim())document.getElementById('csv-label').value=f.name.replace(/\.csv$/i,'');doCsvPreview();}}});})();let _currentGuide=null;async function openGuide(broker_id){const modal=document.getElementById('conn-guide-modal');const body=document.getElementById('guide-body');const title=document.getElementById('guide-title');const sub=document.getElementById('guide-subtitle');const ctaBtn=document.getElementById('guide-cta-btn');modal.classList.add('open');title.textContent='Loading…';sub.textContent='';body.innerHTML='<div style="text-align:center;padding:40px 20px">Loading…</div>';ctaBtn.style.display='none';try{const r=await fetch('/api/brokers/guides/'+broker_id);if(!r.ok)throw new Error('Guide not found');const g=await r.json();_currentGuide=g;title.textContent=g.display_name;sub.textContent=g.subtitle||'';body.innerHTML=renderGuide(g);if(g.cta_label&&g.cta_action){ctaBtn.textContent=g.cta_label;ctaBtn.style.display='';}}catch(e){body.innerHTML=`<div style="text-align:center;padding:40px 20px">Could not load guide.</div>`;}}
