const tagFor=(t)=>{if(t.startsWith('auth.login')||t.startsWith('auth.signup')||t.startsWith('auth.email'))return{icon:'👤',cls:'auth'};if(t.startsWith('auth.'))return{icon:'🔐',cls:'auth'};if(t.startsWith('broker.connection'))return{icon:'🔌',cls:'broker'};if(t.startsWith('broker.disconnected'))return{icon:'❎',cls:'broker'};if(t.startsWith('broker.account'))return{icon:'📊',cls:'broker'};if(t.startsWith('broker.webhook.rejected'))return{icon:'⚠',cls:'fail'};if(t.startsWith('broker.'))return{icon:'🔄',cls:'broker'};if(t.startsWith('billing.payment.failed'))return{icon:'💳',cls:'fail'};if(t.startsWith('billing.'))return{icon:'💰',cls:'billing'};if(t.startsWith('admin.'))return{icon:'🛡',cls:'admin'};if(t.includes('.failure')||t.includes('.rejected')||t.includes('locked'))return{icon:'⚠',cls:'fail'};return{icon:'·',cls:''};};const shown=_admActSize==='all'?rows:rows.slice(0,_admActSize);let html='<table class="adm-table"><thead><tr>'+'<th>When</th><th>User</th><th>Event</th><th>Details</th></tr></thead><tbody>'+
shown.map(ev=>{const t=tagFor(ev.event_type||'');let detail='';try{detail=ev.event_data?JSON.stringify(ev.event_data):'';}catch(e){}
if(detail.length>90)detail=detail.slice(0,87)+'…';return'<tr>'+'<td style="font-size:11px;white-space:nowrap">'+_relativeTime(ev.at)+'</td>'+'<td style="font-size:12px">'+esc(ev.email)+(ev.display_name?' <span style="font-size:10px">('+esc(ev.display_name)+')</span>':'')+'</td>'+'<td><span class="adm-evt adm-evt-'+t.cls+'">'+t.icon+' <span style="font-family:var(--mono);font-size:11px">'+esc(ev.event_type)+'</span></span></td>'+'<td style="font-size:11px;font-family:var(--mono)">'+esc(detail)+'</td>'+'</tr>';}).join('')+'</tbody></table>';if(rows.length>shown.length||filtered){html+='<div style="font-size:11px;color:var(--text3);text-align:center;padding:6px 0 2px">'
+'Showing '+shown.length+' of '+rows.length
+(filtered?' (filtered)':'')+'</div>';}
