const w=150,h=42;let mn=0,mx=0;pts.forEach(v=>{if(v<mn)mn=v;if(v>mx)mx=v;});const range=(mx-mn)||1;const path=pts.map((v,i)=>{const x=pts.length>1?(i/(pts.length-1))*w:0;const y=h-((v-mn)/range)*h;return(i?'L':'M')+x.toFixed(1)+' '+y.toFixed(1);}).join(' ');let posYtd=0;(a.trades||[]).forEach(t=>{if(String(t.date||'').slice(0,4)!==String(yr))return;posYtd+=parseFloat(t.realized_pl||0);});const up=ytd>=0;const lineC=up?'#26A69A':'#E07A75';const kind=(typeof _journalOptionKind==='function')?_journalOptionKind(a):(a.isOption?'Option':'Stock');const upl=a.unrealized_pl||0,rpl=a.realized_pl||0;const plLabel=a.isOpen?'Unrealized':'Realized';const plVal=a.isOpen?upl:rpl;const cc=v=>(v>0?'var(--green)':v<0?'var(--red)':'var(--text)');const chip=(label,val,valC)=>'<div class="jd-ib-chip"><span class="jd-ib-chip-lbl">'+label+'</span>'
