async function saveAlpacaKeys(){const apiKey=(document.getElementById('alpaca-api-key').value||'').trim();const secretKey=(document.getElementById('alpaca-secret-key').value||'').trim();if(!apiKey||!secretKey){connToast('Enter both API Key and Secret','error');return;}
const btn=document.getElementById('alpaca-save-btn');btn.disabled=true;btn.textContent='Testing…';try{const r=await fetch('/api/account/alpaca',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({api_key:apiKey,secret_key:secretKey}),});const data=await r.json();if(!r.ok||!data.ok){connToast(data.error||'Failed to save keys','error');btn.disabled=false;btn.textContent='Activate Alpaca';return;}
connToast('Alpaca connected · '+(data.account_status||'ACTIVE'),'success');document.getElementById('alpaca-api-key').value='';document.getElementById('alpaca-secret-key').value='';_renderAlpacaSettingsUI(data.status);_renderAlpacaWheelPill(data.status);}catch(e){connToast('Network error','error');}finally{btn.disabled=false;btn.textContent='Activate Alpaca';}}
async function testAlpacaConnection(){const btn=document.getElementById('alpaca-test-btn');btn.disabled=true;const orig=btn.textContent;btn.textContent='Testing…';try{const r=await fetch('/api/account/alpaca/test',{method:'POST'});const data=await r.json();if(data.ok)connToast('✓ Alpaca reachable · '+(data.message||'ACTIVE'),'success');else connToast('Test failed: '+(data.message||'Unknown error'),'error');}catch(e){connToast('Network error','error');}finally{btn.disabled=false;btn.textContent=orig;}}
async function toggleAlpaca(enabled){try{const r=await fetch('/api/account/alpaca/toggle',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({enabled:!!enabled}),});const data=await r.json();if(data.ok){_renderAlpacaSettingsUI(data.status);_renderAlpacaWheelPill(data.status);connToast(enabled?'Alpaca enabled':'Alpaca paused','success');}else{connToast(data.error||'Toggle failed','error');const t=document.getElementById('alpaca-toggle');if(t)t.checked=!enabled;}}catch(e){connToast('Network error','error');}}
function showAlpacaKeyEntry(){document.getElementById('alpaca-key-entry').style.display='flex';document.getElementById('alpaca-api-key').focus();}
async function disconnectAlpaca(){if(!(await adminConfirm({title:'Disconnect Alpaca',message:'Disconnect Alpaca? Your saved keys will be deleted from Tradevada.',confirmLabel:'Disconnect',danger:true})))return;try{const r=await fetch('/api/account/alpaca',{method:'DELETE'});const data=await r.json();if(data.ok){connToast('Alpaca disconnected','success');_renderAlpacaSettingsUI({connected:false,enabled:false});_renderAlpacaWheelPill({connected:false,enabled:false});}else{connToast(data.error||'Disconnect failed','error');}}catch(e){connToast('Network error','error');}}
